# solution.py
"""Team Collaboration Manager.

A self-contained, thread-safe, in-memory backend for managing users,
projects, tasks, messaging, performance metrics and reporting.

Standard library only, ASCII only.  Every public read returns deep copies
so callers can never mutate internal state by holding on to a returned
object.  All entity identifiers are drawn from a single, globally unique,
monotonically increasing counter that starts at ``1``.
"""

import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
class User(object):
    __slots__ = ("id", "username", "email", "role", "created_at")

    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at

    def clone(self):
        return User(self.id, self.username, self.email, self.role,
                    self.created_at)

    def __repr__(self):  # pragma: no cover - debugging aid
        return "User(id={0!r}, username={1!r})".format(self.id, self.username)


class Project(object):
    __slots__ = (
        "id", "name", "description", "start_date", "end_date",
        "owner_id", "created_at",
    )

    def __init__(self, id, name, description, start_date, end_date,
                 owner_id, created_at):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.created_at = created_at

    def clone(self):
        return Project(self.id, self.name, self.description, self.start_date,
                       self.end_date, self.owner_id, self.created_at)

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Project(id={0!r}, name={1!r})".format(self.id, self.name)


class Task(object):
    __slots__ = (
        "id", "project_id", "title", "description", "assignee_id",
        "deadline", "status", "started_at", "completed_at", "created_at",
    )

    def __init__(self, id, project_id, title, description, assignee_id,
                 deadline, status, created_at):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.description = description
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.status = status
        self.started_at = None
        self.completed_at = None
        self.created_at = created_at

    def clone(self):
        copy = Task(self.id, self.project_id, self.title, self.description,
                    self.assignee_id, self.deadline, self.status,
                    self.created_at)
        copy.started_at = self.started_at
        copy.completed_at = self.completed_at
        return copy

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Task(id={0!r}, title={1!r}, status={2})".format(
            self.id, self.title, self.status)


class Attachment(object):
    __slots__ = ("filename", "size", "uploaded_by", "uploaded_at")

    def __init__(self, filename, size, uploaded_by, uploaded_at):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at

    def clone(self):
        return Attachment(self.filename, self.size, self.uploaded_by,
                          self.uploaded_at)

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Attachment(filename={0!r}, size={1})".format(
            self.filename, self.size)


class Message(object):
    __slots__ = (
        "id", "author_id", "body", "project_id", "task_id", "parent_id",
        "attachments", "created_at", "edited_at",
    )

    def __init__(self, id, author_id, body, project_id, task_id, parent_id,
                 attachments, created_at):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments if attachments is not None else []
        self.created_at = created_at
        self.edited_at = None

    def clone(self):
        copy = Message(
            self.id, self.author_id, self.body, self.project_id,
            self.task_id, self.parent_id,
            [a.clone() for a in self.attachments], self.created_at,
        )
        copy.edited_at = self.edited_at
        return copy

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Message(id={0!r}, author_id={1!r})".format(
            self.id, self.author_id)


class Rating(object):
    __slots__ = (
        "id", "rater_id", "ratee_id", "score", "feedback", "task_id",
        "created_at",
    )

    def __init__(self, id, rater_id, ratee_id, score, feedback, task_id,
                 created_at):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at

    def clone(self):
        return Rating(self.id, self.rater_id, self.ratee_id, self.score,
                      self.feedback, self.task_id, self.created_at)

    def __repr__(self):  # pragma: no cover - debugging aid
        return "Rating(id={0!r}, score={1})".format(self.id, self.score)


# ---------------------------------------------------------------------------
# Shared store
# ---------------------------------------------------------------------------
class _Store(object):
    """Holds all mutable state plus the single shared lock and id counter."""

    def __init__(self, now_fn):
        self._lock = threading.RLock()
        self._now_fn = now_fn
        self._next_id = 0

        self.users = {}
        self.username_index = {}          # username -> user id
        self.email_index = {}             # lowercased email -> user id

        self.projects = {}

        self.tasks = {}
        self.tasks_by_project = {}        # project id -> set(task ids)
        self.tasks_by_assignee = {}       # user id -> set(task ids)

        self.messages = {}
        self.messages_by_project = {}     # project id -> set(message ids)
        self.messages_by_task = {}        # task id -> set(message ids)

        self.ratings = {}
        self.ratings_by_ratee = {}        # user id -> list(rating ids)

    # -- helpers ----------------------------------------------------------
    def now(self):
        return self._now_fn()

    def next_id(self):
        with self._lock:
            self._next_id += 1
            return self._next_id

    def require_user(self, user_id):
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def require_project(self, project_id):
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def require_task(self, task_id):
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def require_message(self, message_id):
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message


# ---------------------------------------------------------------------------
# Validation helpers
# ---------------------------------------------------------------------------
def _clean_text(value, field):
    if value is None or not isinstance(value, str):
        raise ValidationError("{0} must be a non-empty string".format(field))
    cleaned = value.strip()
    if not cleaned:
        raise ValidationError("{0} must not be empty".format(field))
    return cleaned


def _validate_email(value):
    if value is None or not isinstance(value, str):
        raise ValidationError("email must be a string")
    cleaned = value.strip()
    if not cleaned or "@" not in cleaned:
        raise ValidationError("email is invalid")
    local, _, domain = cleaned.partition("@")
    if not local or not domain:
        raise ValidationError("email is invalid")
    return cleaned


# ---------------------------------------------------------------------------
# User service
# ---------------------------------------------------------------------------
class _UserService(object):
    def __init__(self, store):
        self._store = store
        self._lock = store._lock

    def register_user(self, username, email, role=UserRole.MEMBER):
        clean_name = _clean_text(username, "username")
        clean_email = _validate_email(email)
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")
        email_key = clean_email.lower()
        with self._lock:
            if clean_name in self._store.username_index:
                raise DuplicateError(
                    "username {0!r} already exists".format(clean_name))
            if email_key in self._store.email_index:
                raise DuplicateError(
                    "email {0!r} already exists".format(clean_email))
            user_id = self._store.next_id()
            user = User(user_id, clean_name, clean_email, role,
                        self._store.now())
            self._store.users[user_id] = user
            self._store.username_index[clean_name] = user_id
            self._store.email_index[email_key] = user_id
            return user.clone()

    def get_user(self, user_id):
        with self._lock:
            return self._store.require_user(user_id).clone()

    def list_users(self):
        with self._lock:
            return [self._store.users[uid].clone()
                    for uid in sorted(self._store.users)]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._store.require_user(user_id)

            new_name = None
            if username is not None:
                new_name = _clean_text(username, "username")
                existing = self._store.username_index.get(new_name)
                if existing is not None and existing != user_id:
                    raise DuplicateError(
                        "username {0!r} already exists".format(new_name))

            new_email = None
            email_key = None
            if email is not None:
                new_email = _validate_email(email)
                email_key = new_email.lower()
                existing = self._store.email_index.get(email_key)
                if existing is not None and existing != user_id:
                    raise DuplicateError(
                        "email {0!r} already exists".format(new_email))

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_name is not None and new_name != user.username:
                self._store.username_index.pop(user.username, None)
                user.username = new_name
                self._store.username_index[new_name] = user_id

            if new_email is not None:
                old_key = user.email.lower()
                if old_key != email_key:
                    self._store.email_index.pop(old_key, None)
                user.email = new_email
                self._store.email_index[email_key] = user_id

            if role is not None:
                user.role = role

            return user.clone()

    def delete_user(self, user_id):
        with self._lock:
            self._store.require_user(user_id)

            for project in self._store.projects.values():
                if project.owner_id == user_id:
                    raise ConflictError(
                        "user {0} owns project {1}".format(
                            user_id, project.id))

            assigned = self._store.tasks_by_assignee.get(user_id, set())
            for task_id in assigned:
                task = self._store.tasks.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError(
                        "user {0} has open task {1}".format(user_id, task_id))

            # Detach the (now necessarily completed) tasks from the user.
            for task_id in list(assigned):
                task = self._store.tasks.get(task_id)
                if task is not None:
                    task.assignee_id = None
            self._store.tasks_by_assignee.pop(user_id, None)

            user = self._store.users.pop(user_id)
            self._store.username_index.pop(user.username, None)
            self._store.email_index.pop(user.email.lower(), None)


# ---------------------------------------------------------------------------
# Project service
# ---------------------------------------------------------------------------
class _ProjectService(object):
    def __init__(self, store):
        self._store = store
        self._lock = store._lock

    def create_project(self, name, start_date, end_date, owner_id,
                       description=""):
        clean_name = _clean_text(name, "name")
        if start_date is None or end_date is None:
            raise ValidationError("start_date and end_date are required")
        if end_date < start_date:
            raise ValidationError("end_date must not precede start_date")
        if description is None:
            description = ""
        with self._lock:
            self._store.require_user(owner_id)
            project_id = self._store.next_id()
            project = Project(project_id, clean_name, description, start_date,
                              end_date, owner_id, self._store.now())
            self._store.projects[project_id] = project
            self._store.tasks_by_project[project_id] = set()
            self._store.messages_by_project[project_id] = set()
            return project.clone()

    def get_project(self, project_id):
        with self._lock:
            return self._store.require_project(project_id).clone()

    def list_projects(self):
        with self._lock:
            return [self._store.projects[pid].clone()
                    for pid in sorted(self._store.projects)]

    def update_project(self, project_id, name=None, start_date=None,
                       end_date=None, description=None):
        with self._lock:
            project = self._store.require_project(project_id)

            new_name = None
            if name is not None:
                new_name = _clean_text(name, "name")

            effective_start = start_date if start_date is not None \
                else project.start_date
            effective_end = end_date if end_date is not None \
                else project.end_date
            if effective_end < effective_start:
                raise ValidationError("end_date must not precede start_date")

            if new_name is not None:
                project.name = new_name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return project.clone()

    def delete_project(self, project_id):
        with self._lock:
            self._store.require_project(project_id)

            task_ids = list(self._store.tasks_by_project.get(project_id, set()))
            for task_id in task_ids:
                task = self._store.tasks.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    bucket = self._store.tasks_by_assignee.get(task.assignee_id)
                    if bucket is not None:
                        bucket.discard(task_id)
                # remove any task-scoped messages
                msg_ids = list(self._store.messages_by_task.get(task_id, set()))
                for msg_id in msg_ids:
                    self._store.messages.pop(msg_id, None)
                self._store.messages_by_task.pop(task_id, None)
            self._store.tasks_by_project.pop(project_id, None)

            msg_ids = list(self._store.messages_by_project.get(project_id, set()))
            for msg_id in msg_ids:
                self._store.messages.pop(msg_id, None)
            self._store.messages_by_project.pop(project_id, None)

            self._store.projects.pop(project_id, None)


# ---------------------------------------------------------------------------
# Task service
# ---------------------------------------------------------------------------
class _TaskService(object):
    def __init__(self, store):
        self._store = store
        self._lock = store._lock

    def _validate_deadline(self, project, deadline):
        if deadline is not None and deadline < project.start_date:
            raise ValidationError(
                "deadline must not precede the project start date")

    def create_task(self, project_id, title, assignee_id=None, deadline=None,
                    description=""):
        with self._lock:
            project = self._store.require_project(project_id)
            clean_title = _clean_text(title, "title")
            if assignee_id is not None:
                self._store.require_user(assignee_id)
            self._validate_deadline(project, deadline)
            if description is None:
                description = ""

            task_id = self._store.next_id()
            task = Task(task_id, project_id, clean_title, description,
                        assignee_id, deadline, TaskStatus.NOT_STARTED,
                        self._store.now())
            self._store.tasks[task_id] = task
            self._store.tasks_by_project.setdefault(project_id, set()).add(
                task_id)
            if assignee_id is not None:
                self._store.tasks_by_assignee.setdefault(
                    assignee_id, set()).add(task_id)
            return task.clone()

    def get_task(self, task_id):
        with self._lock:
            return self._store.require_task(task_id).clone()

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._store.require_project(project_id)
            ids = self._store.tasks_by_project.get(project_id, set())
            return [self._store.tasks[tid].clone() for tid in sorted(ids)]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            self._store.require_user(assignee_id)
            ids = self._store.tasks_by_assignee.get(assignee_id, set())
            return [self._store.tasks[tid].clone() for tid in sorted(ids)]

    def _set_assignee(self, task, new_assignee_id):
        old = task.assignee_id
        if old == new_assignee_id:
            return
        if old is not None:
            bucket = self._store.tasks_by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._store.tasks_by_assignee.setdefault(
                new_assignee_id, set()).add(task.id)

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._store.require_task(task_id)
            self._store.require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return task.clone()

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._store.require_task(task_id)
            self._store.require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return task.clone()

    def unassign_task(self, task_id):
        with self._lock:
            task = self._store.require_task(task_id)
            self._set_assignee(task, None)
            return task.clone()

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._store.require_task(task_id)
            project = self._store.require_project(task.project_id)
            self._validate_deadline(project, deadline)
            task.deadline = deadline
            return task.clone()

    def update_status(self, task_id, status):
        with self._lock:
            task = self._store.require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._store.now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return task.clone()


# ---------------------------------------------------------------------------
# Message service
# ---------------------------------------------------------------------------
class _MessageService(object):
    def __init__(self, store):
        self._store = store
        self._lock = store._lock

    def _build_attachments(self, specs, uploader_id):
        attachments = []
        if not specs:
            return attachments
        now = self._store.now()
        for spec in specs:
            filename, data = spec
            clean_name = _clean_text(filename, "filename")
            size = len(data) if data is not None else 0
            attachments.append(
                Attachment(clean_name, size, uploader_id, now))
        return attachments

    def post_message(self, author_id, body, project_id=None, task_id=None,
                     attachments=None, parent_id=None):
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required")

            self._store.require_user(author_id)
            if project_id is not None:
                self._store.require_project(project_id)
            if task_id is not None:
                self._store.require_task(task_id)

            clean_body = body.strip() if isinstance(body, str) else ""
            has_attachments = bool(attachments)
            if not clean_body and not has_attachments:
                raise ValidationError(
                    "message requires a body or at least one attachment")

            if parent_id is not None:
                self._store.require_message(parent_id)

            built = self._build_attachments(attachments, author_id)

            message_id = self._store.next_id()
            stored_body = body if isinstance(body, str) else ""
            message = Message(message_id, author_id, stored_body, project_id,
                              task_id, parent_id, built, self._store.now())
            self._store.messages[message_id] = message
            if project_id is not None:
                self._store.messages_by_project.setdefault(
                    project_id, set()).add(message_id)
            if task_id is not None:
                self._store.messages_by_task.setdefault(
                    task_id, set()).add(message_id)
            return message.clone()

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError(
                    "only the author may edit this message")
            clean_body = new_body.strip() if isinstance(new_body, str) else ""
            if not clean_body and not message.attachments:
                raise ValidationError(
                    "message requires a body or at least one attachment")
            message.body = new_body if isinstance(new_body, str) else ""
            message.edited_at = self._store.now()
            return message.clone()

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may add attachments")
            clean_name = _clean_text(filename, "filename")
            size = len(data) if data is not None else 0
            attachment = Attachment(clean_name, size, uploader_id,
                                    self._store.now())
            message.attachments.append(attachment)
            return message.clone()

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._store.require_project(project_id)
            ids = self._store.messages_by_project.get(project_id, set())
            return [self._store.messages[mid].clone() for mid in sorted(ids)]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._store.require_task(task_id)
            ids = self._store.messages_by_task.get(task_id, set())
            return [self._store.messages[mid].clone() for mid in sorted(ids)]

    def delete_message(self, message_id, actor_id):
        with self._lock:
            message = self._store.require_message(message_id)
            if message.author_id != actor_id:
                raise AuthorizationError(
                    "only the author may delete this message")
            if message.project_id is not None:
                bucket = self._store.messages_by_project.get(
                    message.project_id)
                if bucket is not None:
                    bucket.discard(message_id)
            if message.task_id is not None:
                bucket = self._store.messages_by_task.get(message.task_id)
                if bucket is not None:
                    bucket.discard(message_id)
            self._store.messages.pop(message_id, None)


# ---------------------------------------------------------------------------
# Performance service
# ---------------------------------------------------------------------------
class _PerformanceService(object):
    def __init__(self, store):
        self._store = store
        self._lock = store._lock

    def _user_tasks(self, user_id, project_id=None):
        ids = self._store.tasks_by_assignee.get(user_id, set())
        tasks = [self._store.tasks[tid] for tid in ids
                 if tid in self._store.tasks]
        if project_id is not None:
            tasks = [t for t in tasks if t.project_id == project_id]
        return tasks

    def _completion_rate(self, tasks):
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks
                        if t.status == TaskStatus.COMPLETED)
        return completed / float(len(tasks))

    def _average_completion_time(self, tasks):
        durations = []
        for task in tasks:
            if (task.status == TaskStatus.COMPLETED
                    and task.started_at is not None
                    and task.completed_at is not None):
                delta = task.completed_at - task.started_at
                durations.append(delta.total_seconds())
        if not durations:
            return None
        return sum(durations) / float(len(durations))

    def get_completion_rate(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            return self._completion_rate(self._user_tasks(user_id))

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            return self._average_completion_time(self._user_tasks(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="",
                      task_id=None):
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("users may not rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._store.require_user(rater_id)
            self._store.require_user(ratee_id)
            if task_id is not None:
                self._store.require_task(task_id)
            if feedback is None:
                feedback = ""

            rating_id = self._store.next_id()
            rating = Rating(rating_id, rater_id, ratee_id, score, feedback,
                            task_id, self._store.now())
            self._store.ratings[rating_id] = rating
            self._store.ratings_by_ratee.setdefault(ratee_id, []).append(
                rating_id)
            return rating.clone()

    def _ratings_for(self, user_id):
        ids = self._store.ratings_by_ratee.get(user_id, [])
        return [self._store.ratings[rid] for rid in ids
                if rid in self._store.ratings]

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / float(count)
                       if count else 0.0)
            ordered = sorted(ratings, key=lambda r: r.id)
            return {
                "count": count,
                "average": average,
                "ratings": [r.clone() for r in ordered],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            tasks = self._user_tasks(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks
                            if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks
                              if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks
                              if t.status == TaskStatus.NOT_STARTED)
            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (sum(r.score for r in ratings) /
                              float(rating_count) if rating_count else 0.0)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time":
                    self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


