# Report service
# ---------------------------------------------------------------------------
class _ReportService(object):
    def __init__(self, store, performance):
        self._store = store
        self._lock = store._lock
        self._performance = performance

    def project_progress_report(self, project_id):
        with self._lock:
            self._store.require_project(project_id)
            ids = self._store.tasks_by_project.get(project_id, set())
            tasks = [self._store.tasks[tid] for tid in ids]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / float(total) if total else 0.0

            now = self._store.now()
            overdue = 0
            for task in tasks:
                if (task.deadline is not None
                        and task.status != TaskStatus.COMPLETED
                        and task.deadline < now):
                    overdue += 1

            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                stats = per_assignee.setdefault(
                    task.assignee_id,
                    {"total": 0, "completed": 0, "in_progress": 0,
                     "not_started": 0})
                stats["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    stats["completed"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    stats["in_progress"] += 1
                else:
                    stats["not_started"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _performance_row(self, user_id, project_id=None):
        tasks = self._performance._user_tasks(user_id, project_id)
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        avg_time = self._performance._average_completion_time(tasks)
        ratings = self._performance._ratings_for(user_id)
        rating_count = len(ratings)
        rating_average = (sum(r.score for r in ratings) / float(rating_count)
                          if rating_count else 0.0)
        user = self._store.users.get(user_id)
        username = user.username if user is not None else ""
        return {
            "user_id": user_id,
            "username": username,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": self._performance._completion_rate(tasks),
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._store.require_project(project_id)
                task_ids = self._store.tasks_by_project.get(project_id, set())
                user_ids = set()
                for tid in task_ids:
                    task = self._store.tasks.get(tid)
                    if task is not None and task.assignee_id is not None:
                        user_ids.add(task.assignee_id)
                scope = project_id
                ordered_ids = sorted(user_ids)
            else:
                scope = "global"
                ordered_ids = sorted(self._store.users)

            rows = [self._performance_row(uid, project_id)
                    for uid in ordered_ids]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope": scope,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._store.require_user(user_id)
            tasks = sorted(self._performance._user_tasks(user_id),
                           key=lambda t: t.id)
            total = len(tasks)
            completed = sum(1 for t in tasks
                            if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks
                              if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks
                              if t.status == TaskStatus.NOT_STARTED)
            user = self._store.users.get(user_id)
            task_rows = [
                {
                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username if user is not None else "",
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._performance._completion_rate(tasks),
                "average_completion_time":
                    self._performance._average_completion_time(tasks),
                "tasks": task_rows,
            }

    # -- export -----------------------------------------------------------
    def export_report(self, report, report_format):
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary")
        if report_format == ReportFormat.CSV:
            return self._to_csv(report)
        return self._to_pdf(report)

    def _to_csv(self, report):
        output = io.StringIO()
        writer = csv.writer(output)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = ["user_id", "username", "total_tasks", "completed_tasks",
                      "completion_rate", "average_completion_time",
                      "rating_count", "rating_average"]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([_csv_cell(row.get(col)) for col in header])
        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            writer.writerow(["metric", "value"])
            for key in ("user_id", "username", "total_tasks",
                        "completed_tasks", "in_progress_tasks",
                        "not_started_tasks", "completion_rate",
                        "average_completion_time"):
                writer.writerow([key, _csv_cell(report.get(key))])
            writer.writerow([])
            writer.writerow(["task_id", "project_id", "title", "status"])
            for task in report.get("tasks", []):
                writer.writerow([
                    _csv_cell(task.get("task_id")),
                    _csv_cell(task.get("project_id")),
                    _csv_cell(task.get("title")),
                    _csv_cell(task.get("status")),
                ])
        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", _csv_cell(report.get("project_id"))])
            writer.writerow(["total_tasks", _csv_cell(report.get("total_tasks"))])
            writer.writerow(["completion_rate",
                             _csv_cell(report.get("completion_rate"))])
            writer.writerow(["overdue_tasks",
                             _csv_cell(report.get("overdue_tasks"))])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow(["status:" + str(status), _csv_cell(count)])
            for assignee_id, stats in report.get("per_assignee", {}).items():
                writer.writerow([
                    "assignee:" + str(assignee_id),
                    _csv_cell(stats.get("completed")) + "/"
                    + _csv_cell(stats.get("total")),
                ])
        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([_csv_cell(key), _csv_cell(value)])

        return output.getvalue()

    def _to_pdf(self, report):
        lines = _report_to_lines(report)
        return _build_pdf(lines)


def _csv_cell(value):
    if value is None:
        return ""
    return str(value)


def _report_to_lines(report):
    lines = []
    title = report.get("report_type", "report")
    lines.append("Report: {0}".format(title))
    for key, value in report.items():
        if key == "report_type":
            continue
        if isinstance(value, (list, dict)):
            lines.append("{0}: {1} item(s)".format(key, len(value)))
        else:
            lines.append("{0}: {1}".format(key, value))
    return lines


def _build_pdf(lines):
    """Build a minimal, structurally valid single-page PDF document."""
    content = "BT\n/F1 12 Tf\n72 770 Td\n14 TL\n"
    if not lines:
        lines = ["(empty report)"]
    for line in lines:
        safe = (str(line).replace("\\", "\\\\")
                .replace("(", "\\(").replace(")", "\\)"))
        content += "({0}) Tj\nT*\n".format(safe)
    content += "ET"
    content_bytes = content.encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length " + str(len(content_bytes)).encode("ascii")
        + b" >>\nstream\n" + content_bytes + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    out = bytearray(b"%PDF-1.4\n")
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_pos = len(out)
    count = len(objects) + 1
    out += b"xref\n0 " + str(count).encode("ascii") + b"\n"
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += ("{0:010d} 00000 n \n".format(offset)).encode("ascii")
    out += (b"trailer\n<< /Size " + str(count).encode("ascii")
            + b" /Root 1 0 R >>\nstartxref\n"
            + str(xref_pos).encode("ascii") + b"\n%%EOF")
    return bytes(out)


